// src/utils/pdf.js
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';

export function generateInvoicePDF(order) {
  const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

  const gold = [212, 175, 55];
  const black = [10, 10, 10];
  const white = [255, 255, 255];
  const grey = [60, 60, 60];
  const lgrey = [240, 240, 240];

  // ✅ Price formatter (fix alignment issue)
  const formatPrice = (num) =>
    `₹${Number(num).toLocaleString('en-IN', {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    })}`;

  // ── Header ──
  doc.setFillColor(...black);
  doc.rect(0, 0, 210, 45, 'F');

  doc.setFillColor(...gold);
  doc.rect(0, 45, 210, 1.5, 'F');

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(32);
  doc.setTextColor(...gold);
  doc.text('VAAKIF', 20, 22);

  doc.setFontSize(10);
  doc.setTextColor(...white);
  doc.text('LUXURY ARTIFICIAL JEWELLERY', 20, 30);

  doc.setFontSize(14);
  doc.setTextColor(...gold);
  doc.text('TAX INVOICE', 190, 18, { align: 'right' });

  doc.setFontSize(9);
  doc.setTextColor(200, 200, 200);
  doc.text(`Invoice: ${order.invoice_number || 'N/A'}`, 190, 26, { align: 'right' });
  doc.text(`Order: ${order.order_id}`, 190, 32, { align: 'right' });
  doc.text(`Date: ${new Date().toLocaleDateString('en-IN')}`, 190, 38, { align: 'right' });

  // ── Bill To ──
  let y = 58;

  doc.setTextColor(...gold);
  doc.text('BILL TO', 20, y);

  y += 8;
  doc.setTextColor(...black);
  doc.text(order.customer_name || '', 20, y);

  y += 6;
  doc.setTextColor(...grey);
  doc.text(`Phone: ${order.customer_phone || ''}`, 20, y);

  y += 5;
  doc.text(`Email: ${order.customer_email || ''}`, 20, y);

  // ── Table ──
  y = 100;

  const items = order.items || [];

  const tableBody = items.map((item, i) => [
    i + 1,
    item.name,
    item.category || 'Jewellery',
    item.quantity,
    formatPrice(item.price),
    formatPrice(item.price * item.quantity),
  ]);

  autoTable(doc, {
    startY: y,
    head: [['#', 'Product', 'Category', 'Qty', 'Unit Price', 'Total']],
    body: tableBody,
    margin: { left: 20, right: 20 },
    styles: {
      font: 'helvetica',
      fontSize: 9,
      cellPadding: 3,
      valign: 'middle'
    },
    headStyles: {
      fillColor: gold,
      textColor: black,
      halign: 'center'
    },
    columnStyles: {
      0: { halign: 'center', cellWidth: 10 },
      1: { cellWidth: 65 },
      2: { cellWidth: 30 },
      3: { halign: 'center', cellWidth: 15 },
      4: { halign: 'right', cellWidth: 25 },
      5: { halign: 'right', cellWidth: 25 },
    },
  });

  const finalY = doc.lastAutoTable.finalY + 10;

  // ── Totals ──
  const subtotal = order.subtotal || 0;
  const delivery = order.delivery_charge || 0;
  const total = order.grand_total || 0;

  doc.setFillColor(...lgrey);
  doc.rect(120, finalY, 70, 30, 'F');

  // ✅ Use monospaced font for perfect alignment
  doc.setFont('courier', 'normal');

  doc.setTextColor(...grey);
  doc.text('Subtotal:', 125, finalY + 8);
  doc.text(formatPrice(subtotal), 187, finalY + 8, { align: 'right' });

  doc.text('Delivery:', 125, finalY + 15);
  doc.text(
    delivery === 0 ? 'FREE' : formatPrice(delivery),
    187,
    finalY + 15,
    { align: 'right' }
  );

  doc.setFont('courier', 'bold');
  doc.setTextColor(...black);
  doc.text('Grand Total:', 125, finalY + 25);
  doc.text(formatPrice(total), 187, finalY + 25, { align: 'right' });

  // ── VIEW PDF IN IFRAME ──
  const blob = doc.output('blob');
  const url = URL.createObjectURL(blob);

  document.getElementById('pdfViewer').src = url;
}
